  1→//! Data model for revalidation verdicts and reports.
  2→//!
  3→//! When a previously-interesting input is re-executed against the current
  4→//! version of a function, these types classify what changed and why.
  5→
  6→use serde::{Deserialize, Serialize};
  7→use std::fmt;
  8→use std::time::{SystemTime, UNIX_EPOCH};
  9→
 10→use crate::execution_record::BranchDecision;
 11→use crate::interesting_pool::Severity;
 12→
 13→/// Classification of what happened when replaying a previously-interesting input.
 14→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
 15→#[serde(rename_all = "snake_case")]
 16→pub enum RevalidationVerdict {
 17→    /// Behavior unchanged — same branch path and severity.
 18→    Confirmed,
 19→    /// Code fingerprint changed and behavior changed — expected drift.
 20→    ExpectedDrift,
 21→    /// Code unchanged but behavior changed — nondeterminism or environment.
 22→    Flaky,
 23→    /// Code changed and previously-interesting behavior vanished.
 24→    PotentialRegression,
 25→    /// Behavior became less severe (potential silent fix).
 26→    SeverityDowngrade,
 27→    /// Behavior became more severe (potential new bug).
 28→    SeverityUpgrade,
 29→}
 30→
 31→impl fmt::Display for RevalidationVerdict {
 32→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 33→        match self {
 34→            Self::Confirmed => write!(f, "confirmed"),
 35→            Self::ExpectedDrift => write!(f, "expected drift"),
 36→            Self::Flaky => write!(f, "flaky"),
 37→            Self::PotentialRegression => write!(f, "potential regression"),
 38→            Self::SeverityDowngrade => write!(f, "severity downgrade"),
 39→            Self::SeverityUpgrade => write!(f, "severity upgrade"),
 40→        }
 41→    }
 42→}
 43→
 44→/// Result of re-executing a previously-interesting input against the current code.
 45→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 46→pub struct RevalidationReport {
 47→    /// Fully qualified function name.
 48→    pub function_name: String,
 49→    /// The input vector that was replayed.
 50→    pub input_vector: Vec<serde_json::Value>,
 51→    /// Branch path from the original exploration.
 52→    pub expected_branch_path: Vec<BranchDecision>,
 53→    /// Branch path observed during revalidation.
 54→    pub observed_branch_path: Vec<BranchDecision>,
 55→    /// Severity from the original exploration.
 56→    pub expected_severity: Severity,
 57→    /// Severity observed during revalidation, or `None` if the behavior vanished.
 58→    pub observed_severity: Option<Severity>,
 59→    /// Classification of the revalidation outcome.
 60→    pub verdict: RevalidationVerdict,
 61→    /// Milliseconds since Unix epoch when the revalidation was performed.
 62→    pub timestamp_epoch_ms: u64,
 63→}
 64→
 65→/// Returns the current time as milliseconds since Unix epoch.
 66→pub fn now_epoch_ms() -> u64 {
 67→    SystemTime::now()
 68→        .duration_since(UNIX_EPOCH)
 69→        .unwrap_or_default()
 70→        .as_millis() as u64
 71→}
 72→
 73→/// Classify a revalidation outcome into a verdict.
 74→///
 75→/// Priority order: severity changes take precedence over path changes when
 76→/// both the path and severity differ, because severity shifts have more
 77→/// actionable signal. When only the path changed, we distinguish code-change
 78→/// drift from flaky nondeterminism.
 79→pub fn classify_verdict(
 80→    code_changed: bool,
 81→    path_matches: bool,
 82→    expected_severity: Severity,
 83→    observed_severity: Option<Severity>,
 84→) -> RevalidationVerdict {
 85→    match observed_severity {
 86→        // Behavior vanished entirely.
 87→        None => {
 88→            if code_changed {
 89→                RevalidationVerdict::PotentialRegression
 90→            } else {
 91→                RevalidationVerdict::Flaky
 92→            }
 93→        }
 94→        Some(observed) => {
 95→            // Check severity shift first — more actionable than path changes.
 96→            if observed < expected_severity {
 97→                return RevalidationVerdict::SeverityDowngrade;
 98→            }
 99→            if observed > expected_severity {
100→                return RevalidationVerdict::SeverityUpgrade;
101→            }
102→            // Same severity — classify based on path match.
103→            if path_matches {
104→                RevalidationVerdict::Confirmed
105→            } else if code_changed {
106→                RevalidationVerdict::ExpectedDrift
107→            } else {
108→                RevalidationVerdict::Flaky
109→            }
110→        }
111→    }
112→}
113→
