242→    use std::collections::{HashMap, HashSet};
243→
244→    fn sample_analysis() -> FunctionAnalysis {
245→        FunctionAnalysis {
246→            name: "add".to_string(),
247→            exported: true,
248→            params: vec![
249→                ParamInfo {
250→                    name: "a".into(),
251→                    typ: TypeInfo::Int,
252→                    type_name: None,
253→                },
254→                ParamInfo {
255→                    name: "b".into(),
256→                    typ: TypeInfo::Int,
257→                    type_name: None,
258→                },
259→            ],
260→            branches: vec![BranchInfo {
261→                id: 0,
262→                line: 3,
263→                condition_text: "a > 0".into(),
264→                condition: None,
265→                branch_type: BranchType::If,
266→            }],
267→            dependencies: vec![],
268→            return_type: TypeInfo::Int,
