276→    #[test]
277→    fn identical_inputs_produce_same_fingerprint() {
278→        let analysis = sample_analysis();
279→        let source = "function add(a, b) {\n  if (a > 0) return a + b;\n  return b;\n}";
280→
281→        let fp1 = compute_function_fingerprint(source, &analysis);
282→        let fp2 = compute_function_fingerprint(source, &analysis);
283→
284→        assert_eq!(fp1, fp2);
285→        assert_eq!(fp1.len(), 64); // SHA-256 hex = 64 chars
286→    }
