387→/// Paths exercised by at most this many inputs qualify as rare during harvesting.
388→pub const DEFAULT_RARITY_THRESHOLD: u32 = 2;
389→
390→/// Harvest interesting inputs from raw exploration results into the pool.
391→///
392→/// Decomposes each execution's input vector into individual `(value, TypeInfo)`
393→/// pairs, filters out boundary-dict values (already tried everywhere), classifies
394→/// severity, and inserts into the pool. For error-triggering executions all inputs
395→/// are harvested; for non-error executions only those on rare paths (exercised by
396→/// ≤ `DEFAULT_RARITY_THRESHOLD` inputs) are kept.
397→///
398→/// Returns the number of pool entries inserted or merged.
399→pub fn harvest_from_exploration(
400→    pool: &mut InterestingPool,
401→    raw_results: &[(Vec<serde_json::Value>, ExecuteResult)],
402→    params: &[ParamInfo],
403→    function_name: &str,
404→) -> usize {
405→    if raw_results.is_empty() || params.is_empty() {
406→        return 0;
407→    }
408→
409→    // Build path frequency map for rarity classification.
410→    let mut path_counts: HashMap<u64, u32> = HashMap::new();
411→    let hashes: Vec<u64> = raw_results
412→        .iter()
413→        .map(|(_, result)| {
414→            let h = explorer::path_hash(result, &explorer::LoopBuckets::default());
415→            *path_counts.entry(h).or_default() += 1;
416→            h
417→        })
418→        .collect();
419→
420→    // Pre-compute boundary value sets per parameter position for filtering.
421→    let boundary_sets: Vec<HashSet<serde_json::Value>> = params
422→        .iter()
423→        .map(|p| {
424→            boundary_dict::get_boundary_values(&p.typ)
425→                .into_iter()
426→                .map(|entry| entry.value)
427→                .collect()
428→        })
429→        .collect();
430→
431→    let epoch = pool.epoch;
432→    let mut inserted = 0;
433→
434→    for (idx, (inputs, exec_result)) in raw_results.iter().enumerate() {
435→        let severity = classify_severity(exec_result.thrown_error.as_ref(), false);
436→
437→        // For RarePath, only harvest if the path is actually rare.
438→        if severity == Severity::RarePath {
439→            let count = path_counts.get(&hashes[idx]).copied().unwrap_or(0);
440→            if count > DEFAULT_RARITY_THRESHOLD {
441→                continue;
442→            }
443→        }
444→
445→        // Determine branch_id from execution's branch path.
446→        let branch_id = exec_result
447→            .branch_path
448→            .last()
449→            .map(|d| d.branch_id)
450→            .unwrap_or(0);
451→
452→        let obs = BehaviorObservation {
453→            function: function_name.to_string(),
454→            branch_id,
455→            severity,
456→        };
457→
458→        // Decompose input vector into individual (value, type) entries.
459→        for (i, value) in inputs.iter().enumerate() {
460→            if i >= params.len() {
461→                break;
462→            }
463→
464→            // Skip boundary-dict values — they're tried everywhere already.
465→            if boundary_sets[i].contains(value) {
466→                continue;
467→            }
468→
469→            let entry = PoolEntry {
470→                value: value.clone(),
471→                ty: params[i].typ.clone(),
472→                behaviors: vec![obs.clone()],
473→                discovered_epoch: epoch,
474→                last_hit_epoch: epoch,
475→            };
476→
477→            if pool.insert(entry) {
478→                inserted += 1;
479→            }
480→        }
481→
482→        // For multi-param functions with compound types, also store the full
483→        // input vector so correlated multi-arg patterns are preserved.
484→        if params.len() > 1
485→            && inputs.iter().zip(params.iter()).any(|(_, p)| {
486→                matches!(p.typ, TypeInfo::Object { .. } | TypeInfo::Array { .. })
487→            })
488→        {
489→            let compound_type = TypeInfo::Array {
490→                element: Box::new(TypeInfo::Unknown),
491→            };
492→            let compound_entry = PoolEntry {
493→                value: serde_json::Value::Array(inputs.clone()),
494→                ty: compound_type,
495→                behaviors: vec![obs],
496→                discovered_epoch: epoch,
497→                last_hit_epoch: epoch,
498→            };
499→            if pool.insert(compound_entry) {
500→                inserted += 1;
501→            }
502→        }
503→    }
504→
505→    inserted
506→}
