226→/// Extract the list of solvable `SymExpr` path conditions from an execution result's branch path.
227→///
228→/// Each constraint is adjusted based on the `taken` field so that negating it
229→/// in the solver produces inputs that flip the branch:
230→/// - `taken=true`: the path condition is the constraint itself
231→/// - `taken=false`: the path condition is `NOT(constraint)`, because the branch
232→///   condition evaluated to false
233→///
234→/// Returns `None` for branches with `Unknown` constraints; those are skipped
235→/// by the solver but may be targeted by fuzzing.
236→fn extract_sym_constraints(result: &ExecuteResult) -> Vec<Option<SymExpr>> {
237→    result
238→        .branch_path
239→        .iter()
240→        .map(|decision| match &decision.constraint {
241→            SymConstraint::Expr { expr } => {
242→                if decision.taken {
243→                    Some(expr.clone())
244→                } else {
245→                    // The branch was not taken, so the actual path condition
246→                    // is NOT(constraint). Wrapping it here ensures that when
247→                    // the solver negates this entry, it produces the raw
248→                    // constraint — i.e., the condition needed to take the branch.
249→                    Some(SymExpr::UnOp {
250→                        op: crate::sym_expr::UnOpKind::Not,

  1→//! Data model for revalidation verdicts and reports.
  2→//!
  3→//! When a previously-interesting input is re-executed against the current
  4→//! version of a function, these types classify what changed and why.
  5→
  6→use serde::{Deserialize, Serialize};
  7→use std::fmt;
  8→use std::time::{SystemTime, UNIX_EPOCH};
  9→
 10→use crate::execution_record::BranchDecision;
 11→use crate::interesting_pool::Severity;
 12→
 13→/// Classification of what happened when replaying a previously-interesting input.
 14→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
 15→#[serde(rename_all = "snake_case")]
 16→pub enum RevalidationVerdict {
 17→    /// Behavior unchanged — same branch path and severity.
 18→    Confirmed,
 19→    /// Code fingerprint changed and behavior changed — expected drift.
 20→    ExpectedDrift,
 21→    /// Code unchanged but behavior changed — nondeterminism or environment.
 22→    Flaky,
 23→    /// Code changed and previously-interesting behavior vanished.
 24→    PotentialRegression,
 25→    /// Behavior became less severe (potential silent fix).
 26→    SeverityDowngrade,
 27→    /// Behavior became more severe (potential new bug).
 28→    SeverityUpgrade,
 29→}
 30→
 31→impl fmt::Display for RevalidationVerdict {
 32→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 33→        match self {
 34→            Self::Confirmed => write!(f, "confirmed"),
 35→            Self::ExpectedDrift => write!(f, "expected drift"),
 36→            Self::Flaky => write!(f, "flaky"),
 37→            Self::PotentialRegression => write!(f, "potential regression"),
 38→            Self::SeverityDowngrade => write!(f, "severity downgrade"),
 39→            Self::SeverityUpgrade => write!(f, "severity upgrade"),
 40→        }
 41→    }
 42→}
 43→
 44→/// Result of re-executing a previously-interesting input against the current code.
 45→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 46→pub struct RevalidationReport {
 47→    /// Fully qualified function name.
 48→    pub function_name: String,
 49→    /// The input vector that was replayed.
 50→    pub input_vector: Vec<serde_json::Value>,
 51→    /// Branch path from the original exploration.
 52→    pub expected_branch_path: Vec<BranchDecision>,
 53→    /// Branch path observed during revalidation.
 54→    pub observed_branch_path: Vec<BranchDecision>,
 55→    /// Severity from the original exploration.
 56→    pub expected_severity: Severity,
 57→    /// Severity observed during revalidation, or `None` if the behavior vanished.
 58→    pub observed_severity: Option<Severity>,
 59→    /// Classification of the revalidation outcome.
 60→    pub verdict: RevalidationVerdict,
 61→    /// Milliseconds since Unix epoch when the revalidation was performed.
 62→    pub timestamp_epoch_ms: u64,
 63→}
 64→
 65→/// Returns the current time as milliseconds since Unix epoch.
 66→pub fn now_epoch_ms() -> u64 {
 67→    SystemTime::now()
 68→        .duration_since(UNIX_EPOCH)
 69→        .unwrap_or_default()
 70→        .as_millis() as u64
 71→}
 72→
 73→/// Classify a revalidation outcome into a verdict.
 74→///
 75→/// Priority order: severity changes take precedence over path changes when
 76→/// both the path and severity differ, because severity shifts have more
 77→/// actionable signal. When only the path changed, we distinguish code-change
 78→/// drift from flaky nondeterminism.
 79→pub fn classify_verdict(
 80→    code_changed: bool,
 81→    path_matches: bool,
 82→    expected_severity: Severity,
 83→    observed_severity: Option<Severity>,
 84→) -> RevalidationVerdict {
 85→    match observed_severity {
 86→        // Behavior vanished entirely.
 87→        None => {
 88→            if code_changed {
 89→                RevalidationVerdict::PotentialRegression
 90→            } else {
 91→                RevalidationVerdict::Flaky
 92→            }
 93→        }
 94→        Some(observed) => {
 95→            // Check severity shift first — more actionable than path changes.
 96→            if observed < expected_severity {
 97→                return RevalidationVerdict::SeverityDowngrade;
 98→            }
 99→            if observed > expected_severity {
100→                return RevalidationVerdict::SeverityUpgrade;
101→            }
102→            // Same severity — classify based on path match.
103→            if path_matches {
104→                RevalidationVerdict::Confirmed
105→            } else if code_changed {
106→                RevalidationVerdict::ExpectedDrift
107→            } else {
108→                RevalidationVerdict::Flaky
109→            }
110→        }
111→    }
112→}
113→
114→#[cfg(test)]
115→mod tests {
116→    use super::*;
117→
118→    #[test]
119→    fn confirmed_when_nothing_changed() {
120→        let v = classify_verdict(false, true, Severity::RarePath, Some(Severity::RarePath));
121→        assert_eq!(v, RevalidationVerdict::Confirmed);
122→    }
123→
124→    #[test]
125→    fn confirmed_when_code_changed_but_behavior_identical() {
126→        let v = classify_verdict(true, true, Severity::HandledError, Some(Severity::HandledError));
127→        assert_eq!(v, RevalidationVerdict::Confirmed);
128→    }
129→
130→    #[test]
131→    fn expected_drift_when_code_changed_and_path_differs() {
132→        let v = classify_verdict(true, false, Severity::RarePath, Some(Severity::RarePath));
133→        assert_eq!(v, RevalidationVerdict::ExpectedDrift);
134→    }
135→
136→    #[test]
137→    fn flaky_when_code_unchanged_but_path_differs() {
138→        let v = classify_verdict(false, false, Severity::RarePath, Some(Severity::RarePath));
139→        assert_eq!(v, RevalidationVerdict::Flaky);
140→    }
141→
142→    #[test]
143→    fn potential_regression_when_code_changed_and_behavior_vanished() {
144→        let v = classify_verdict(true, false, Severity::UnhandledError, None);
145→        assert_eq!(v, RevalidationVerdict::PotentialRegression);
146→    }
147→
148→    #[test]
149→    fn flaky_when_code_unchanged_and_behavior_vanished() {
150→        let v = classify_verdict(false, false, Severity::Crash, None);
151→        assert_eq!(v, RevalidationVerdict::Flaky);
152→    }
153→
154→    #[test]
155→    fn severity_downgrade() {
156→        let v = classify_verdict(
157→            true,
158→            false,
159→            Severity::UnhandledError,
160→            Some(Severity::RarePath),
161→        );
162→        assert_eq!(v, RevalidationVerdict::SeverityDowngrade);
163→    }
164→
165→    #[test]
166→    fn severity_upgrade() {
167→        let v = classify_verdict(
168→            false,
169→            true,
170→            Severity::RarePath,
171→            Some(Severity::Crash),
172→        );
173→        assert_eq!(v, RevalidationVerdict::SeverityUpgrade);
174→    }
175→
176→    #[test]
177→    fn severity_upgrade_takes_precedence_over_path_match() {
178→        // Even though path matches, severity increased — report as upgrade.
179→        let v = classify_verdict(
180→            false,
181→            true,
182→            Severity::HandledError,
183→            Some(Severity::UnhandledError),
184→        );
185→        assert_eq!(v, RevalidationVerdict::SeverityUpgrade);
186→    }
187→
188→    #[test]
189→    fn severity_downgrade_takes_precedence_over_drift() {
190→        // Code changed and path differs, but severity decreased — report as downgrade.
191→        let v = classify_verdict(
192→            true,
193→            false,
194→            Severity::Crash,
195→            Some(Severity::HandledError),
196→        );
197→        assert_eq!(v, RevalidationVerdict::SeverityDowngrade);
198→    }
199→
200→    #[test]
201→    fn display_impl() {
202→        assert_eq!(RevalidationVerdict::Confirmed.to_string(), "confirmed");
203→        assert_eq!(RevalidationVerdict::ExpectedDrift.to_string(), "expected drift");
204→        assert_eq!(RevalidationVerdict::Flaky.to_string(), "flaky");
205→        assert_eq!(
206→            RevalidationVerdict::PotentialRegression.to_string(),
207→            "potential regression"
208→        );
209→        assert_eq!(
210→            RevalidationVerdict::SeverityDowngrade.to_string(),
211→            "severity downgrade"
212→        );
213→        assert_eq!(
214→            RevalidationVerdict::SeverityUpgrade.to_string(),
215→            "severity upgrade"
216→        );
217→    }
218→
219→    #[test]
220→    fn verdict_serde_round_trip() {
221→        let verdicts = [
222→            RevalidationVerdict::Confirmed,
223→            RevalidationVerdict::ExpectedDrift,
224→            RevalidationVerdict::Flaky,
225→            RevalidationVerdict::PotentialRegression,
226→            RevalidationVerdict::SeverityDowngrade,
227→            RevalidationVerdict::SeverityUpgrade,
228→        ];
229→        for v in &verdicts {
230→            let json = serde_json::to_string(v).expect("serialize verdict");
231→            let restored: RevalidationVerdict =
232→                serde_json::from_str(&json).expect("deserialize verdict");
233→            assert_eq!(*v, restored);
234→        }
235→    }
236→
237→    #[test]
238→    fn report_serde_round_trip() {
239→        use crate::execution_record::SymConstraint;
240→
241→        let report = RevalidationReport {
242→            function_name: "validateEmail".into(),
243→            input_vector: vec![serde_json::json!("test@example.com")],
244→            expected_branch_path: vec![BranchDecision {
245→                branch_id: 1,
246→                taken: true,
247→                line: 5,
248→                constraint: SymConstraint::Unknown {
249→                    hint: "email.includes('@')".into(),
250→                },
251→            }],
252→            observed_branch_path: vec![BranchDecision {
253→                branch_id: 1,
254→                taken: false,
255→                line: 5,
256→                constraint: SymConstraint::Unknown {
257→                    hint: "email.includes('@')".into(),
258→                },
259→            }],
260→            expected_severity: Severity::RarePath,
261→            observed_severity: Some(Severity::HandledError),
262→            verdict: RevalidationVerdict::SeverityUpgrade,
263→            timestamp_epoch_ms: 1_700_000_000_000,
264→        };
265→
266→        let json = serde_json::to_string(&report).expect("serialize report");
267→        let restored: RevalidationReport =
268→            serde_json::from_str(&json).expect("deserialize report");
269→        assert_eq!(report, restored);
270→    }
271→
272→    #[test]
273→    fn now_epoch_ms_returns_reasonable_value() {
274→        let ms = now_epoch_ms();
275→        // Should be after 2020-01-01 (1_577_836_800_000 ms).
276→        assert!(ms > 1_577_836_800_000);
277→    }
278→}
