// ---------------------------------------------------------------------------
// BehaviorMap
// ---------------------------------------------------------------------------

/// A single observed behavior: specific inputs produced specific outputs.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct Behavior {
    pub id: u32,
    pub input_args: Vec<serde_json::Value>,
    pub return_value: Option<serde_json::Value>,
    pub thrown_error: Option<ErrorInfo>,
    pub branch_path: Vec<BranchDecision>,
    pub side_effects: Vec<SideEffect>,
    /// Full dependency interaction trace, present when the execution involved
    /// external calls or side effects.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub dependency_trace: Option<DependencyTrace>,
}

/// All observed behaviors for a function, built from execution records.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct BehaviorMap {
    pub function_id: String,
    pub behaviors: Vec<Behavior>,
    /// SHA-256 fingerprint of the function's source, params, and branches.
    /// Used for staleness detection: if the fingerprint matches a cached value,
    /// the function is unchanged and can be skipped during re-exploration.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub fingerprint: Option<String>,
    /// Fields identified as nondeterministic during exploration.
    /// Populated from the nondeterminism detection report when available.
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub nondeterministic_fields: Vec<crate::nondeterminism::NondeterministicField>,
}

impl BehaviorMap {
    /// Build a behavior map from execution records, deduplicating by `input_hash`.
    pub fn from_records(function_id: impl Into<String>, records: &[ExecutionRecord]) -> Self {
        let mut seen_hashes = HashSet::new();
        let mut behaviors = Vec::new();
        let mut next_id: u32 = 0;

        for record in records {
            if !seen_hashes.insert(record.input_hash) {
                continue;
            }
            let dependency_trace =
                if record.calls_to_external.is_empty() && record.side_effects.is_empty() {
                    None
                } else {
                    Some(build_dependency_trace_from_record(record))
                };
            behaviors.push(Behavior {
                id: next_id,
                input_args: record.parameters.clone(),
                return_value: record.return_value.clone(),
                thrown_error: record.thrown_error.clone(),
                branch_path: record.branch_path.clone(),
                side_effects: record.side_effects.clone(),
                dependency_trace,
            });
            next_id += 1;
        }

        Self {
            function_id: function_id.into(),
            behaviors,
            fingerprint: None,
            nondeterministic_fields: vec![],
        }
    }

    /// Build a behavior map from an [`ObservationOutput`](crate::explorer::ObservationOutput).
    ///
    /// Converts each [`ExecutionSummary`](crate::explorer::ExecutionSummary) that discovered
    /// a new path into a [`Behavior`] entry. When raw results are available,
    /// dependency traces are populated from the matching [`ExecuteResult`].
    pub fn from_exploration_result(
        function_id: impl Into<String>,
        result: &crate::explorer::ObservationOutput,
    ) -> Self {
        let behaviors = result
            .new_path_executions
            .iter()
            .enumerate()
            .map(|(i, exec)| {
                let thrown_error = exec.thrown_error.as_ref().map(|msg| ErrorInfo {
                    error_type: "Error".to_string(),
                    message: msg.clone(),
                    stack: None, error_category: None });
                // Try to find the matching raw result for this execution to
                // extract the dependency trace.
                let dependency_trace = result
                    .raw_results
                    .iter()
                    .find(|(inputs, _)| *inputs == exec.inputs)
                    .filter(|(_, res)| {
                        !res.calls_to_external.is_empty() || !res.side_effects.is_empty()
                    })
                    .map(|(_, res)| build_dependency_trace(res));

//! Frontend subprocess manager for spawning and communicating with language frontends.
//!
//! The core engine communicates with frontends via newline-delimited JSON over stdin/stdout.
//! This module handles subprocess lifecycle (spawn, handshake, request/response, shutdown)
//! and provides a typed async API over the raw protocol.

use std::path::PathBuf;
use std::process::Stdio;
use std::time::Duration;

use tokio::io::{AsyncBufReadExt, AsyncWriteExt, BufReader};
use tokio::process::{Child, Command};

use crate::protocol::{Command as ProtoCommand, Request, Response, ResponseResult, PROTOCOL_VERSION};

/// Default timeout for individual frontend requests (30 seconds).
pub const DEFAULT_REQUEST_TIMEOUT: Duration = Duration::from_secs(30);

/// Grace period to wait for the frontend process to exit during shutdown
/// before force-killing it.
const SHUTDOWN_GRACE_PERIOD: Duration = Duration::from_secs(5);

/// Errors that can occur when communicating with a frontend subprocess.
#[derive(Debug, thiserror::Error)]
pub enum FrontendError {
    /// Failed to spawn the frontend process.
    #[error("failed to spawn frontend: {0}")]
    Spawn(std::io::Error),

    /// Failed to write a request to the frontend's stdin.
    #[error("failed to write to frontend stdin: {0}")]
    Write(std::io::Error),

    /// Failed to read a response from the frontend's stdout.
    #[error("failed to read from frontend stdout: {0}")]
    Read(std::io::Error),

    /// The frontend process closed its stdout unexpectedly.
    #[error("frontend closed stdout unexpectedly")]
    UnexpectedEof,

    /// Failed to serialize a request to JSON.
    #[error("failed to serialize request: {0}")]
    Serialize(serde_json::Error),

    /// Failed to deserialize a response from JSON.
    #[error("failed to deserialize response: {0}")]
    Deserialize(serde_json::Error),

    /// The response ID did not match the request ID.
    #[error("response id {response_id} does not match request id {request_id}")]
    IdMismatch { request_id: u64, response_id: u64 },

    /// The frontend returned a protocol error response.
    #[error("frontend error ({code:?}): {message}")]
    Protocol {
        code: crate::protocol::ErrorCode,
        message: String,
        details: Option<serde_json::Value>,
    },

    /// A request timed out waiting for a response.
    #[error("request timed out after {0:?}")]
    Timeout(Duration),

    /// The frontend process exited unexpectedly.
    #[error("frontend process exited with status: {0}")]
    ProcessExited(std::process::ExitStatus),

    /// Protocol version mismatch during handshake.
    #[error("protocol version mismatch: core={core}, frontend={frontend}")]
    VersionMismatch { core: String, frontend: String },
}

/// Configuration for spawning a frontend subprocess.
#[derive(Debug, Clone)]
pub struct FrontendConfig {
    /// Path to the frontend binary or script.
    pub command: PathBuf,
    /// Arguments to pass to the frontend.

